"""Embedding + Chroma vector-store factory (spec §4.4).

Uses Ollama's ``nomic-embed-text`` model by default. The same persist directory
holds all collections (``docs``, ``history``, optional ``web``).
"""

from __future__ import annotations

from functools import lru_cache


def make_embeddings(settings):
    from langchain_ollama import OllamaEmbeddings

    return OllamaEmbeddings(
        model=settings.embed_model,
        base_url=settings.ollama_host,
    )


@lru_cache(maxsize=8)
def _cached_store(collection: str, chroma_dir: str, embed_model: str, ollama_host: str):
    from langchain_chroma import Chroma
    from langchain_ollama import OllamaEmbeddings

    embeddings = OllamaEmbeddings(model=embed_model, base_url=ollama_host)
    return Chroma(
        collection_name=collection,
        embedding_function=embeddings,
        persist_directory=chroma_dir,
    )


def get_vector_store(settings, collection: str = "docs"):
    """Return a persistent Chroma store for a named collection."""
    settings.chroma_dir.mkdir(parents=True, exist_ok=True)
    return _cached_store(
        collection,
        str(settings.chroma_dir),
        settings.embed_model,
        settings.ollama_host,
    )

"""Responders: turn an :class:`AgentRequest` into a text reply.

``DirectResponder`` (M1) does a single-shot Ollama chat with the persona system
prompt. ``AgentResponder`` (M2) wraps the stateful LangGraph react agent. Both
satisfy the ``Responder`` signature used by :class:`bot.router.Router`.
"""

from __future__ import annotations

import json
import logging

from ai.ollama_client import OllamaClient
from ai.persona import build_system_prompt
from bot.router import AgentRequest
from storage.db import Database

log = logging.getLogger("tramice.responder")

OLLAMA_DOWN = "Mon moteur de réflexion est indisponible. Vérifie qu'Ollama tourne."


def load_social_norms(db: Database) -> dict:
    """Read the current social-norm booleans from ``app.sqlite``."""
    norms: dict = {}
    for row in db.query_app("SELECT key, value FROM social_norms"):
        try:
            norms[row["key"]] = json.loads(row["value"])
        except (json.JSONDecodeError, TypeError):
            norms[row["key"]] = row["value"]
    return norms


class DirectResponder:
    """Stateless single-turn responder (M1 baseline)."""

    def __init__(self, ollama: OllamaClient, db: Database):
        self._ollama = ollama
        self._db = db

    async def respond(self, req: AgentRequest) -> str:
        if not await self._ollama.ping():
            return OLLAMA_DOWN
        system = build_system_prompt(req.surface, load_social_norms(self._db))
        messages = [
            {"role": "system", "content": system},
            {"role": "user", "content": req.content},
        ]
        try:
            return await self._ollama.chat(messages)
        except Exception as exc:  # noqa: BLE001
            log.exception("Ollama chat failed")
            return OLLAMA_DOWN if "connect" in str(exc).lower() else (
                "Oups, une petite turbulence de mon côté. Peux-tu reformuler ?"
            )

"""Configuration loader: merges `config.yaml` with `.env` secrets.

Exposes a single `Settings` object (via `load_settings`) that the rest of the
app reads. Values from `config.yaml` are the defaults; environment variables
supply secrets and deployment-specific IDs.
"""

from __future__ import annotations

import os
from dataclasses import dataclass, field
from pathlib import Path
from typing import Any

import yaml
from dotenv import load_dotenv

PROJECT_ROOT = Path(__file__).resolve().parent.parent
DATA_DIR = PROJECT_ROOT / "data"
DOCS_DIR = PROJECT_ROOT / "docs"
PROMPTS_DIR = PROJECT_ROOT / "prompts"


def _split_ids(raw: str | None) -> list[str]:
    if not raw:
        return []
    return [part.strip() for part in raw.split(",") if part.strip()]


@dataclass
class Settings:
    """Resolved configuration for a running bot process."""

    # Raw merged config tree (from config.yaml).
    raw: dict[str, Any] = field(default_factory=dict)

    # Secrets / environment.
    discord_token: str = ""
    ollama_host: str = "http://127.0.0.1:11434"
    guild_id: str | None = None
    admin_role_ids: list[str] = field(default_factory=list)

    # Paths.
    project_root: Path = PROJECT_ROOT
    data_dir: Path = DATA_DIR
    docs_dir: Path = DOCS_DIR
    prompts_dir: Path = PROMPTS_DIR

    # ---- convenience accessors ----------------------------------------
    def get(self, dotted_key: str, default: Any = None) -> Any:
        """Fetch a nested config value, e.g. ``get("llm.model")``."""
        node: Any = self.raw
        for part in dotted_key.split("."):
            if isinstance(node, dict) and part in node:
                node = node[part]
            else:
                return default
        return node

    @property
    def bot_name(self) -> str:
        return self.get("bot.name", "Tramice721")

    @property
    def prefix(self) -> str:
        return self.get("bot.prefix", "!ai")

    @property
    def locale_default(self) -> str:
        return self.get("bot.locale_default", "fr")

    @property
    def timezone(self) -> str:
        return self.get("bot.timezone", "America/Montreal")

    @property
    def model(self) -> str:
        return self.get("llm.model", "qwen2.5:7b-instruct")

    @property
    def temperature(self) -> float:
        return float(self.get("llm.temperature", 0.7))

    @property
    def max_tokens(self) -> int:
        return int(self.get("llm.max_tokens", 2048))

    @property
    def embed_model(self) -> str:
        return self.get("llm.embed_model", "nomic-embed-text")

    @property
    def summary_channel_id(self) -> str | None:
        val = self.get("channels.summary_channel_id")
        return str(val) if val not in (None, "", "null") else None

    # DB / vector store paths (kept in one place).
    @property
    def app_db_path(self) -> Path:
        return self.data_dir / "app.sqlite"

    @property
    def history_db_path(self) -> Path:
        return self.data_dir / "history.sqlite"

    @property
    def checkpoints_db_path(self) -> Path:
        return self.data_dir / "checkpoints.sqlite"

    @property
    def chroma_dir(self) -> Path:
        return self.data_dir / "chroma"


def load_settings(config_path: Path | None = None) -> Settings:
    """Load `.env` then `config.yaml` into a `Settings` object."""
    load_dotenv(PROJECT_ROOT / ".env")

    config_path = config_path or (PROJECT_ROOT / "config.yaml")
    raw: dict[str, Any] = {}
    if config_path.exists():
        with config_path.open("r", encoding="utf-8") as fh:
            raw = yaml.safe_load(fh) or {}

    settings = Settings(
        raw=raw,
        discord_token=os.getenv("DISCORD_TOKEN", ""),
        ollama_host=os.getenv("OLLAMA_HOST", "http://127.0.0.1:11434"),
        guild_id=os.getenv("GUILD_ID") or None,
        admin_role_ids=_split_ids(os.getenv("ADMIN_ROLE_IDS")),
    )

    settings.data_dir.mkdir(parents=True, exist_ok=True)
    return settings

"""Observability: structured logging + append-only audit trail (spec §10.4, §11.2)."""

from __future__ import annotations

import hashlib
import json
import logging
from datetime import datetime, timezone
from pathlib import Path

from bot.config import PROJECT_ROOT

AUDIT_PATH = PROJECT_ROOT / "audit.log"

_STD_ATTRS = set(
    logging.LogRecord("", 0, "", 0, "", (), None).__dict__.keys()
) | {"message", "asctime"}


class JsonFormatter(logging.Formatter):
    """Emit one JSON object per log line (spec §11.2)."""

    def format(self, record: logging.LogRecord) -> str:
        payload = {
            "ts": datetime.now(timezone.utc).isoformat(),
            "level": record.levelname,
            "logger": record.name,
            "event": record.getMessage(),
        }
        for key, value in record.__dict__.items():
            if key not in _STD_ATTRS and not key.startswith("_"):
                payload[key] = value
        if record.exc_info:
            payload["exc"] = self.formatException(record.exc_info)
        return json.dumps(payload, ensure_ascii=False)


def audit(user_id: str, action: str, tool: str | None = None, args: dict | None = None,
          result: str = "ok") -> None:
    """Append an audit record. Arguments are hashed, never stored verbatim."""
    args_hash = ""
    if args:
        raw = json.dumps(args, sort_keys=True, ensure_ascii=False)
        args_hash = hashlib.sha256(raw.encode("utf-8")).hexdigest()[:16]
    record = {
        "ts": datetime.now(timezone.utc).isoformat(),
        "user_id": user_id,
        "action": action,
        "tool": tool,
        "args_hash": args_hash,
        "result": result,
    }
    try:
        with AUDIT_PATH.open("a", encoding="utf-8") as fh:
            fh.write(json.dumps(record, ensure_ascii=False) + "\n")
    except OSError:
        logging.getLogger("tramice.audit").warning("Could not write audit log")
